<?php
class AiEyeController {
public static function store(): void { $u=$GLOBALS['auth_user']; $d=Request::json(); $db=Database::connection(); $p=$db->prepare('SELECT id FROM patients WHERE user_id=?');$p->execute([$u['id']]);$pid=$p->fetch()['id']??null; if(!$pid) Response::json(false,'Pasien tidak ditemukan'); [$risk,$sum,$rec]=AiEyeRiskService::analyze($d['symptoms']??[],$d['duration']??'',(int)($d['pain_level']??0)); $s=$db->prepare('INSERT INTO ai_eye_screenings (patient_id,complaint_text,symptoms,duration,pain_level,photo_path,risk_level,analysis_summary,recommendation,rule_version,created_at) VALUES (?,?,?,?,?,?,?,?,?,?,NOW())'); $s->execute([$pid,$d['complaint_text']??'',json_encode($d['symptoms']??[]),$d['duration']??'',(int)($d['pain_level']??0),$d['photo_path']??null,$risk,$sum,$rec,'1.0']); $id=(int)$db->lastInsertId(); $db->prepare('INSERT INTO audit_logs (user_id,action,entity,entity_id,ip_address,user_agent,created_at) VALUES (?,?,?,?,?,?,NOW())')->execute([$u['id'],'buat_ai_screening','ai_eye_screenings',$id,$_SERVER['REMOTE_ADDR']??null,$_SERVER['HTTP_USER_AGENT']??null]); Response::json(true,'Screening berhasil dianalisis',['id'=>$id,'risk_level'=>$risk,'summary'=>$sum,'recommendation'=>$rec,'disclaimer'=>'Hasil AI bukan diagnosis dokter.']); }
public static function index(): void { $id=$GLOBALS['auth_user']['id']; $db=Database::connection(); $s=$db->prepare('SELECT a.* FROM ai_eye_screenings a JOIN patients p ON p.id=a.patient_id WHERE p.user_id=? ORDER BY a.id DESC'); $s->execute([$id]); Response::json(true,'Data berhasil dimuat',$s->fetchAll()); }
public static function show($id): void { $u=$GLOBALS['auth_user']['id']; $s=Database::connection()->prepare('SELECT a.* FROM ai_eye_screenings a JOIN patients p ON p.id=a.patient_id WHERE p.user_id=? AND a.id=?'); $s->execute([$u,$id]); Response::json(true,'Data berhasil dimuat',$s->fetch()); }
}
